// // This module implements a 5-bit Johnson counter that generates a sequence of states with a single '1' bit propagating through the register followed by '0' bits. The sequence repeats every 10 cycles.
module johnson_counter(clk, q);

    input  clk;  
    output [4:0] q;  
    reg    [4:0] q; 
    initial q = 5'b00001;

    always @(posedge clk)
        begin
            q <= {q[3:0], ~q[4]};
        end  

endmodule
